import React, { useCallback } from 'react';
import { PeriodActionPanel } from '../../../components/kt/PeriodActionPanel';
import { ktService } from '../../../services/kt/ktService';
import { PERIOD_JOB_TYPES } from '../../../constants/periodJobTypes';
import { PERIOD_REFERENCE_NO } from '../../../constants/periodProcessReferences';
import { periodProcessStatusLabel } from '../../../utils/periodProcessStatusLabel';

const KetChuyenKyPage: React.FC = () => {
  const getStatus = useCallback(
    async (m: number, y: number) => periodProcessStatusLabel(await ktService.getPeriodClosingStatus(m, y)),
    [],
  );

  return (
    <PeriodActionPanel
      testIdPrefix="kt-ket-chuyen-cuoi-ky"
      title="Kết chuyển cuối kỳ"
      icon="fa-exchange-alt"
      runLabel="Kết chuyển"
      postLabel="Ghi sổ"
      jobType={PERIOD_JOB_TYPES.PeriodClosing}
      referenceNo={PERIOD_REFERENCE_NO.Closing}
      getStatus={getStatus}
      onRun={(m, y) => ktService.runPeriodClosing(m, y)}
      onPost={(m, y) => ktService.postPeriodClosing(m, y)}
    />
  );
};

export default KetChuyenKyPage;
